        .rpg-opt-left { display: flex; align-items: flex-start; flex: 1; }
        .rpg-opt-num { opacity: 0.3; margin-right: 12px; font-family: monospace; min-width: 15px; }
        .rpg-opt-tag { font-weight: bold; margin-right: 8px; color: #fff; opacity: 0.9; }

        /* 后果标记样式 */
        .rpg-opt-impact {
            font-size: 10px; color: #666; margin-left: 10px; 
            font-family: sans-serif; opacity: 0.7; white-space: nowrap;
            align-self: center; /* 垂直居中 */
        }

        .rpg-opt-btn.is-attack:hover { color: #ff4d4d; border-left-color: #ff4d4d; }
