        try {
            var root = this.parentNode;
            var rawText = root.querySelector('.raw-data').innerText;
            var ui = root.querySelector('.ui-container');
            var header = root.querySelector('.rpg-header');

            header.onclick = function() {
                ui.style.display = (ui.style.display === 'none') ? 'flex' : 'none';
                this.style.opacity = (ui.style.display === 'none') ? '0.7' : '1';
            };

            if (ui.children.length > 0) return;

            var lines = rawText.split('\n');
            for (var i = 0; i < lines.length; i++) {
                var line = lines[i].trim();
                if (!line) continue;

                // 正则解析：序号 + [标签] + 内容 + (后果)
                var match = line.match(/^(\d+|Last|Final)\.\s*(?:\[(.*?)\])?\s*(.*?)(?:\s*(\([^\)]+\)))?$/);
                var num = '', tag = '', content = line, impact = '', textToCopy = line, isAttack = false;

                if (match) {
                    num = match[1]; 
                    tag = match[2] || ''; 
                    content = match[3];
                    impact = match[4] || ''; // 提取后果标记

                    // 复制时只包含标签和内容，不包含后果
                    textToCopy = (tag ? '[' + tag + '] ' : '') + content;

                    if (content.includes('攻击') || content.includes('Attack') || num === 'Last') {
                        isAttack = true; num = '⚔️'; 
                    }
                }

                var btn = document.createElement('div');
                btn.className = 'rpg-opt-btn' + (isAttack ? ' is-attack' : '');

                // 构建 HTML
                var leftPart = '<div class=\'rpg-opt-left\'>' + 
                               (num ? '<span class=\'rpg-opt-num\'>'+num+'</span>' : '') + 
                               (tag ? '<span class=\'rpg-opt-tag\'>['+tag+']</span>' : '') + 
                               '<span>' + content + '</span></div>';

                var rightPart = impact ? '<span class=\'rpg-opt-impact\'>' + impact + '</span>' : '';

                btn.innerHTML = leftPart + rightPart;

                (function(txt, elem){
                    elem.onclick = function() {
                        try {
                            var input = window.parent.document.getElementById('send_textarea') || document.getElementById('send_textarea');
                            if (input) {
                                input.value = txt;
                                input.dispatchEvent(new Event('input', { bubbles: true }));
                                input.focus();
                            } else if (navigator.clipboard) {
                                navigator.clipboard.writeText(txt);
                            }
                        } catch(e){}
                    };
                })(textToCopy, btn);

                ui.appendChild(btn);
            }
            this.remove();
        } catch(e) {}
    ">
</div>
