    // === 渲染逻辑 ===
    function renderCard(label, val, desc, container, disabled = false) {
        const div = document.createElement('div');
        div.className = `option-card ${disabled ? 'disabled' : ''}`;
        div.dataset.value = val;
        div.innerHTML = `<div class="option-name">${label}</div>${desc ? `<div class="option-desc">${desc}</div>` : ''}`;
        container.appendChild(div);
    }

    // 初始化渲染
    Object.keys(races).forEach(k => renderCard(k, k, races[k].desc, dom.raceGrid));
    psionicTypes.forEach(k => renderCard(k, k, '', dom.psiTypeGrid)); // 动态生成星能
    subClasses.forEach(k => renderCard(k, k, '', dom.subClassGrid));

    // === 交互逻辑 ===
    document.addEventListener('click', e => {
        const card = e.target.closest('.option-card');
        if (!card || card.classList.contains('disabled')) return;

        const grid = card.parentElement;
        const group = grid.dataset.group;
        const value = card.dataset.value;

        // UI 更新
        grid.querySelectorAll('.option-card').forEach(c => c.classList.remove('selected'));
        card.classList.add('selected');

        // 状态更新
        state[group] = value;
        handleSideEffects(group, value);
        updateStats(); 
        checkCompletion();
    });

    ['name', 'age', 'custom-race-input', 'custom-bg-input', 'custom-subclass-input', 'supplement'].forEach(id => {
        const el = document.getElementById(id);
        el.addEventListener('input', e => {
            if (id === 'name') state.name = e.target.value;
            if (id === 'age') {
                state.age = e.target.value;
                // 年龄改变触发背景列表刷新
                if (state.faction) handleSideEffects('faction', state.faction);
            }
            if (id === 'custom-race-input') state.customRace = e.target.value;
            if (id === 'custom-bg-input') state.customBg = e.target.value;
            if (id === 'custom-subclass-input') state.customSubClass = e.target.value;
            if (id === 'supplement') state.supplement = e.target.value;
            checkCompletion();
        });
    });

    // === 核心逻辑处理 ===
    function handleSideEffects(group, val) {
        // 1. 性别改变
        if (group === 'gender') {
            if (state.faction) renderBackgrounds(state.faction);
        }

        // 2. 种族改变
        if (group === 'race') {
            state.subRace = null;
            state.customRace = '';
            dom.subRaceArea.style.display = 'none';
            dom.customRaceInput.style.display = 'none';

            if (val === '自定义') {
                dom.customRaceInput.style.display = 'block';
            } else if (subRaces[val]) {
                dom.subRaceArea.style.display = 'block';
                dom.subRaceGrid.innerHTML = '';
                subRaces[val].forEach(sub => renderCard(sub, sub, '', dom.subRaceGrid));
            }

            const raceData = races[val];
            if (raceData && raceData.forcePsionic) {
                state.forcePsionicLock = true;
                state.hasPsionic = 'true';
                lockPsionicUI(true);
            } else {
                state.forcePsionicLock = false;
                lockPsionicUI(false); 
            }

            renderFactions(val);
            renderClasses(val); 
            checkEmpirePsiAlert();
        }

        // 3. 亚种改变
        if (group === 'subRace') {
            if (state.faction) renderBackgrounds(state.faction);
        }

        // 4. 势力改变
        if (group === 'faction') {
            renderBackgrounds(val);
            renderClasses(state.race); 
            checkEmpirePsiAlert();
        }

        // 5. 出身改变
        if (group === 'background') {
            // 重置锁定状态
            lockSubClassUI(false); 
            lockPsionicTypeUI(false);

            if (val === '自定义') {
                dom.customBgInput.style.display = 'block';
                dom.bgDescDisplay.style.display = 'none';
            } else {
                dom.customBgInput.style.display = 'none';
                const bg = backgrounds[val];
                if (bg) {
                    dom.bgDescDisplay.style.display = 'block';
                    dom.bgDescDisplay.textContent = bg.desc;

                    // 强制灵能
                    if (bg.forcePsionic) {
                        state.forcePsionicLock = true;
                        state.hasPsionic = 'true';
                        lockPsionicUI(true);
                    } else if (!races[state.race]?.forcePsionic) {
                         state.forcePsionicLock = false;
                         lockPsionicUI(false);
                    }

                    // 强制星能类型 (锁定UI)
                    if (bg.forcePsiType) {
                        state.psionicType = bg.forcePsiType;
                        updatePsiTypeUI(bg.forcePsiType);
                        lockPsionicTypeUI(true); // 锁定
                    }

                    // 强制副职业 (锁定UI)
                    if (bg.forceSubClass) {
                        state.subClass = bg.forceSubClass;
                        // 如果副职业列表里没有，临时添加
                        if (!subClasses.includes(bg.forceSubClass)) {
                            // 清除旧的临时卡片
                            const oldTemp = Array.from(dom.subClassGrid.children).find(c => !subClasses.includes(c.dataset.value));
                            if (oldTemp && oldTemp.dataset.value !== bg.forceSubClass) oldTemp.remove();
                            // 添加新卡片
                            if (!dom.subClassGrid.querySelector(`[data-value="${bg.forceSubClass}"]`)) {
                                renderCard(bg.forceSubClass, bg.forceSubClass, '特殊限定', dom.subClassGrid);
                            }
                        }

                        // 刷新选中状态
                        dom.subClassGrid.querySelectorAll('.option-card').forEach(c => {
                            c.classList.toggle('selected', c.dataset.value === bg.forceSubClass);
                        });

                        lockSubClassUI(true); // 锁定
                    }
                }
            }
            checkEmpirePsiAlert();
        }

        // 6. 星能改变
        if (group === 'hasPsionic') {
            dom.psiTypeArea.style.display = (val === 'true') ? 'block' : 'none';
            checkEmpirePsiAlert();
        }

        // 7. 副职业
        if (group === 'subClass') {
            dom.customSubClassInput.style.display = (val === '自定义') ? 'block' : 'none';
        }
    }

    function checkEmpirePsiAlert() {
        if (state.faction === '奥古斯都帝国' && state.hasPsionic === 'true' && state.background !== '审判庭学徒') {
            dom.empirePsiAlert.style.display = 'block';
        } else {
            dom.empirePsiAlert.style.display = 'none';
        }
    }

    function lockPsionicUI(locked) {
        dom.psiLockBadge.style.display = locked ? 'inline-block' : 'none';
        if (locked) {
            dom.psiNo.classList.add('disabled');
            dom.psiYes.classList.add('selected');
            dom.psiNo.classList.remove('selected');
            dom.psiTypeArea.style.display = 'block';
        } else {
            dom.psiNo.classList.remove('disabled');
        }
    }

    // 锁定副职业UI
    function lockSubClassUI(locked) {
        dom.subClassGrid.querySelectorAll('.option-card').forEach(c => {
            if (locked) {
                if (!c.classList.contains('selected')) c.classList.add('disabled');
            } else {
                c.classList.remove('disabled');
            }
        });
    }

    // 清理非常规副职业 (新函数)
    function cleanSpecialSubClass() {
        if (state.subClass && !subClasses.includes(state.subClass)) {
            state.subClass = null; // 重置状态
            dom.customSubClassInput.style.display = 'none';

            // 移除临时DOM
            Array.from(dom.subClassGrid.children).forEach(c => {
                if (!subClasses.includes(c.dataset.value)) c.remove();
                else c.classList.remove('selected'); // 取消其他选中
            });
        }
    }

    // 锁定星能类型UI
    function lockPsionicTypeUI(locked) {
        dom.psiTypeGrid.querySelectorAll('.option-card').forEach(c => {
            if (locked) {
                if (!c.classList.contains('selected')) c.classList.add('disabled');
            } else {
                c.classList.remove('disabled');
            }
        });
    }

    function updatePsiTypeUI(type) {
        dom.psiTypeGrid.querySelectorAll('.option-card').forEach(c => {
            if(c.dataset.value === type) c.classList.add('selected');
            else c.classList.remove('selected');
        });
    }

    function renderFactions(race) {
        dom.factionGrid.innerHTML = '';
        state.faction = null;
        state.background = null; 
        dom.bgGrid.innerHTML = '<div class="option-card disabled"><div class="option-name">请先选择势力</div></div>';

        Object.keys(factions).forEach(key => {
            const fac = factions[key];
            let visible = false;
            if (fac.races.length === 0) visible = true; 
            else if (race === '自定义' && fac.races.includes('自定义')) visible = true;
            else if (fac.races.includes(race)) visible = true;
            if (visible) renderCard(key, key, '', dom.factionGrid);
        });
    }

    function renderBackgrounds(faction) {
        dom.bgArea.style.display = 'block'; 

        // 关键逻辑：先检查当前已选中的背景是否还合法
        let currentBgValid = false;
        const oldBackground = state.background;

        dom.bgGrid.innerHTML = '';

        const currentRace = state.race;
        const currentAge = parseInt(state.age) || 25;

        let isAlienGuest = false;
        if (faction === '天琴联邦' && ['纽特', '巴洛克混血'].includes(currentRace)) isAlienGuest = true;
        if (faction === '圣临教团' && ['萨尔贡', '巴洛克混血'].includes(currentRace)) isAlienGuest = true;
        const forceSlave = (faction === '猩红教团' && currentRace === '萨尔贡');
        const forcePet = (faction === '萨尔贡议会' && currentRace === '扎尔');

        Object.keys(backgrounds).forEach(key => {
            const bg = backgrounds[key];
            let visible = true;

            // 检查逻辑
            if (Array.isArray(bg.faction)) {
                if (!bg.faction.includes(faction)) visible = false;
            } else {
                if (bg.faction !== faction && bg.faction !== '自定义') visible = false;
            }

            if (forceSlave && key !== '星能奴隶') visible = false;
            if (forcePet && key !== '秘密宠物') visible = false;
            if (bg.reqAgeMax && currentAge > bg.reqAgeMax) visible = false;
            if (bg.reqGender) {
                const reqs = Array.isArray(bg.reqGender) ? bg.reqGender : [bg.reqGender];
                if (!reqs.includes(state.gender)) visible = false;
            }
            if (bg.reqSubRace) {
                if (!state.subRace || state.subRace !== bg.reqSubRace) visible = false;
            }
            if (bg.reqRace) {
                if (currentRace !== bg.reqRace) visible = false;
            }
            // 新增: 排除种族
            if (bg.excludeRace) {
                const excluded = Array.isArray(bg.excludeRace) ? bg.excludeRace : [bg.excludeRace];
                if (excluded.includes(currentRace)) visible = false;
            }

            if (!forceSlave && !forcePet && isAlienGuest) {
                if (bg.tier === 'high' || bg.tier === 'low') visible = false;
            }

            if (visible) {
                renderCard(key, key, '', dom.bgGrid);
                if (key === oldBackground) currentBgValid = true;
            }
        });

        if (!forceSlave && !forcePet) {
            renderCard('自定义', '自定义', '', dom.bgGrid);
            if (oldBackground === '自定义') currentBgValid = true;
        }

        // 核心修复：如果当前背景不再合法，重置所有相关状态
        if (oldBackground && !currentBgValid) {
            state.background = null;
            state.customBg = '';
            dom.bgDescDisplay.style.display = 'none';
            // 解锁UI并清理特殊副职业
            lockSubClassUI(false); 
            cleanSpecialSubClass(); // 强力清洗
            lockPsionicTypeUI(false);
            state.forcePsionicLock = false;
            lockPsionicUI(false);
        } else if (oldBackground) {
            const card = dom.bgGrid.querySelector(`[data-value="${oldBackground}"]`);
            if (card) card.classList.add('selected');
        }
    }

    function renderClasses(race) {
        dom.classGrid.innerHTML = '';
        state.mainClass = null;
        Object.keys(mainClasses).forEach(key => {
            const cls = mainClasses[key];
            let visible = true;
            // 种族检查
            if (cls.reqRace && cls.reqRace !== race) visible = false;
            // 势力检查 (新逻辑)
            if (cls.reqFaction && cls.reqFaction !== state.faction) visible = false;

            if (visible) renderCard(key, key, cls.desc, dom.classGrid);
        });
    }

    function updateStats() {
        dom.statsDisplay.innerHTML = '';
        ATTRS.forEach((attr, idx) => {
            let val = 30;
            if (state.race && races[state.race]) val = races[state.race].stats[idx];

            if (state.background && state.background !== '自定义') {
                const bg = backgrounds[state.background];
                if (bg && bg.stats[attr]) val += bg.stats[attr];
            }

            if (state.mainClass) {
                const cls = mainClasses[state.mainClass];
                if (cls && cls.bonus[attr]) val += cls.bonus[attr];
            }

            const bonus = Math.floor((val - 30) / 10);
            const color = bonus > 0 ? 'var(--highlight-color)' : (bonus < 0 ? '#ff4d4d' : '#94a3b8');

            const row = document.createElement('div');
            row.className = 'stat-row';
            row.innerHTML = `<span class="stat-name">${attr}</span><div><span class="stat-val">${val}</span><span class="bonus-val" style="color:${color}">(${bonus>=0?'+':''}${bonus})</span></div>`;
            dom.statsDisplay.appendChild(row);
        });

        let order = 0, good = 0;
        let tags = [];
        let items = [];
        let desc = '暂无';

        if (state.background && state.background !== '自定义') {
            const bg = backgrounds[state.background];
            if (bg) {
                order = bg.align[0];
                good = bg.align[1];
                tags = [...bg.tags];
                items = [...bg.items];
                desc = bg.desc;
            }
        }

        // 更新阵营数值和进度条
        dom.orderVal.textContent = order;
        dom.goodVal.textContent = good;
        dom.chaosBar.style.width = (order < 0 ? Math.min(Math.abs(order), 100) : 0) + '%';
        dom.orderBar.style.width = (order > 0 ? Math.min(order, 100) : 0) + '%';
        dom.evilBar.style.width = (good < 0 ? Math.min(Math.abs(good), 100) : 0) + '%';
        dom.goodBar.style.width = (good > 0 ? Math.min(good, 100) : 0) + '%';

        dom.tagsDisplay.innerHTML = tags.map(t => `<span class="tag-pill">${t}</span>`).join('');
        dom.itemsDisplay.innerHTML = items.map(i => `<div style="margin-bottom:2px;">• ${i}</div>`).join('');
        dom.bgStoryDisplay.textContent = desc; 
    }

    function checkCompletion() {
        let valid = true;
        if (!state.name) valid = false;
        if (!state.gender) valid = false;
        if (!state.race) valid = false;
        if (races[state.race]?.hasSub && !state.subRace) valid = false;
        if (state.race === '自定义' && !state.customRace) valid = false;
        if (!state.faction) valid = false;
        if (!state.background) valid = false; 
        if (state.background === '自定义' && !state.customBg) valid = false;
        if (state.hasPsionic === 'true' && !state.psionicType) valid = false;
        if (!state.mainClass) valid = false;
        if (!state.subClass) valid = false; 
        if (state.subClass === '自定义' && !state.customSubClass) valid = false;

        dom.createBtn.disabled = !valid;
        dom.createBtn.textContent = valid ? '生成档案' : '档案不完整';
    }

    dom.createBtn.addEventListener('click', () => {
        if (dom.createBtn.disabled) return;

        const finalRace = state.race === '自定义' ? state.customRace : (state.subRace ? `${state.race}(${state.subRace})` : state.race);
        const finalBg = state.background === '自定义' ? `自定义: ${state.customBg}` : state.background; 
        const psionicStr = state.hasPsionic === 'true' ? `星能者 - ${state.psionicType}` : '无星能';
        const finalSubClass = state.subClass === '自定义' ? state.customSubClass : state.subClass;

        let tagsStr = '';
        let itemsStr = '';
        let bgDesc = '';

        if (state.background !== '自定义') {
            const bg = backgrounds[state.background];
            if (bg) {
                tagsStr = bg.tags.join(', ');
                itemsStr = bg.items.join(', ');
                bgDesc = bg.desc;
            }
        }

        const summary = [
            '奥德赛传奇 · 角色档案',
            `姓名: ${state.name}`,
            `年龄: ${state.age}`,
            `性别: ${state.gender}`,
            `种族: ${finalRace}`,
            `势力: ${state.faction}`,
            `背景: ${finalBg}`,
            `经历: ${bgDesc}`, 
            `职业: ${state.mainClass}`,
            `副职业: ${finalSubClass}`,
            `星能: ${psionicStr}`,
            `特性: ${tagsStr || '无'}`,
            `物资: ${itemsStr}`,
            `备注: ${state.supplement || '无'}`
        ].join('\n');

        if (typeof TavernHelper !== 'undefined') {
            TavernHelper.createChatMessages([{ role: 'user', message: summary }]).then(() => {
                TavernHelper.triggerSlash('/trigger');
            });
        } else {
            try {
                const chatInput = window.parent.document.getElementById('send_textarea') || document.getElementById('send_textarea');
                chatInput.value = summary;
                chatInput.dispatchEvent(new Event('input', { bubbles: true }));
                chatInput.focus();
            } catch(e) {
                navigator.clipboard.writeText(summary);
                alert('已复制档案！请粘贴到聊天框。');
            }
        }
    });
});
</script>
</body>
</html>
