            <div class="card-detail">
              <div style="margin-bottom:8px; padding:4px; background:rgba(0,0,0,0.2); border-radius:4px;">
                <div style="color:#888;font-size:10px;margin-bottom:2px">任务简报</div>
                <div style="color:#ccc">${v.描述 || v.说明 || '无详细说明'}</div>
                <div style="text-align:right;color:#666;font-size:9px;margin-top:2px">— ${v.发布人 || '系统终端'}</div>
              </div>

              <div style="display:flex; gap:6px;">
                ${v.奖励 ? `<div style="flex:1; border:1px solid rgba(76, 255, 136, 0.2); background:rgba(76, 255, 136, 0.05); padding:4px; border-radius:4px;"><div style="color:#4f8;font-size:10px">🎁 奖励</div><div style="color:#ada;font-size:10px">${rewardText}</div></div>` : ''}
                ${v.惩罚 ? `<div style="flex:1; border:1px solid rgba(255, 85, 85, 0.2); background:rgba(255, 85, 85, 0.05); padding:4px; border-radius:4px;"><div style="color:#f55;font-size:10px">⚠️ 风险</div><div style="color:#faa;font-size:10px">${v.惩罚}</div></div>` : ''}
              </div>
            </div>
          </div>`;
        });
      }
      $('#quest-list').html(qHtml);

      // === PAGE 3: Logs ===
      const logs = hero.重大历史经历 ? Object.values(hero.重大历史经历) : [];
      // Schema是对象，需要转数组并倒序
      const sortedLogs = logs.reverse();

      let lHtml = '<div class="section-title">⭐ 光辉事迹</div>';
      if(sortedLogs.length === 0) lHtml += '<div class="empty-state">暂无事迹</div>';
      else sortedLogs.forEach(h => {
        lHtml += `<div style="margin-bottom:10px;padding-left:10px;border-left:2px solid var(--theme-color)">
          <div style="display:flex;justify-content:space-between;font-size:10px;color:#888">
            <span>${h.发生时间}</span>
            <span style="color:var(--theme-color)">[${h.传阅度||'未知'}]</span>
          </div>
          <div style="color:#ddd;font-weight:bold;margin:2px 0">${h.事件名}</div>
          <div style="font-size:11px;color:#aaa">${h.描述}</div>
        </div>`;
      });

      const archives = _.get(all, 'stat_data.任务档案', {});
      lHtml += '<div class="section-title">📁 档案记录</div>';
      if(Object.keys(archives).length === 0) lHtml += '<div class="empty-state">暂无档案</div>';
      else Object.entries(archives).reverse().forEach(([k,v]) => lHtml+=`<div style="margin-bottom:8px;font-size:11px"><span style="color:#888">[${v.时间}]</span> <span style="color:#ccc">${k}</span>: ${v.结果}</div>`);
      $('#timeline').html(lHtml);

// === PAGE 4: ASSETS (带品质边框版) ===
      const vs = hero.载具||{};
      let aHtml = '<div class="section-title">🚀 载具机库</div>';

      // 辅助函数：获取品质样式类
      const getQClass = (q) => {
        const map = {
          '破损': 'q-broken', '废物': 'q-trash', 
          '普通': 'q-common', '精良': 'q-good', 
          '稀有': 'q-rare',   '史诗': 'q-epic', 
          '传说': 'q-legend', '神话': 'q-mythic'
        };
        return map[q] || 'q-common';
      };

      const renderV = (v,n) => {
        if(!v||v.名称==='无') return '';
        const hp = v.状态?.最大耐久 > 0 ? (v.状态.当前耐久 / v.状态.最大耐久) * 100 : 0;
        return `<div class="list-card" onclick="toggleDetail(this)">
          <div class="card-head"><span class="card-title">${v.名称}</span></div>
          <div style="height:4px;background:#333;margin-top:4px"><div style="height:100%;width:${hp}%;background:${hp<30?'#f55':'#4f8'}"></div></div>
          <div class="card-detail">能源: ${v.状态?.能源||0}%</div>
        </div>`;
      };
      const v1 = renderV(vs.当前机甲);
      const v2 = renderV(vs.当前舰船);
      if(!v1 && !v2) aHtml+='<div class="empty-state">无载具</div>';
      else aHtml += v1 + v2;

      const eq = hero.装备栏||{};
      aHtml += '<div class="section-title">⚔️ 当前装备</div>';

      // 装备渲染：加入 getQClass
      const renderE = (i, slot) => i && i.名称!=='无' ? 
        `<div class="list-card ${getQClass(i.品质)}" onclick="toggleDetail(this)">
          <div class="card-head"><span class="card-title">${i.名称}</span><span style="font-size:10px;color:#888">${slot}</span></div>
          <div class="card-detail">品质: ${i.品质}<br>属性: ${i.属性}<br>${i.描述}</div>
        </div>` : 
        `<div class="empty-slot"><span>${slot}</span><span style="color:#555">空置</span></div>`;

      aHtml += renderE(eq.主手, '主手');
      aHtml += renderE(eq.副手, '副手');
      aHtml += renderE(eq.护甲, '护甲');
      aHtml += renderE(eq.饰品, '饰品');

      aHtml += '<div class="section-title">🎒 背包物品</div>';
      const bagItems = eq.背包物品 ? Object.values(eq.背包物品) : [];

      if(bagItems.length) {
        bagItems.forEach(i => {
          if (!i || i.名称 === '损坏') return;
          // 背包渲染：加入 getQClass
          aHtml += `<div class="list-card ${getQClass(i.品质)}" onclick="toggleDetail(this)">
            <div class="card-head"><span class="card-title">${i.名称}</span><span style="color:var(--theme-color)">x${i.数量||1}</span></div>
            <div class="card-detail">品质: ${i.品质}<br>属性: ${i.属性}<br>${i.描述}</div>
          </div>`;
        });
      } else {
        aHtml += '<div class="empty-state">背包为空</div>';
      }
      $('#asset-list').html(aHtml);

      // === PAGE 5: SOCIAL ===
      const soc = hero.人脉||{};
      let sHtml = '';
      let impH='<div class="section-title">⭐ 重要关系</div>', normH='<div class="section-title">👥 泛泛之交</div>';
      const enemyName = target.名称 || '';

      Object.entries(soc).forEach(([k,v]) => {
        if (k === enemyName) return; 

        let det=''; 
        Object.entries(v).forEach(([kk,vv])=> {
            if (typeof vv !== 'object' && kk !== '属性') det+=`${kk}: ${vv}<br>`;
        });

        const item = `<div class="list-card" style="border-color:${v.类型==='重要'?'var(--theme-color)':'#444'}" onclick="toggleDetail(this)">
          <div class="card-head"><span class="card-title" style="color:${v.类型==='重要'?'#fff':'#ccc'}">${k}</span><span style="font-weight:bold;color:${v.好感度>0?'#4f8':'#f55'}">${v.好感度}</span></div>
          <div class="card-sub">${v.种族} | ${v.关系||'未知'}</div>
          <div class="card-detail">${det}</div>
        </div>`;
        v.类型==='重要'?impH+=item:normH+=item;
      });
      sHtml += impH + normH;

      // 势力声望 (已修复对象读取)
      sHtml += '<div class="section-title">🏛️ 势力声望</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
      const reps = _.get(all, 'stat_data.势力声望', {});

      Object.entries(reps).forEach(([k, rawVal]) => {
        // 兼容处理：如果是新版对象结构取.声望值，如果是旧版数字直接用
        const val = (typeof rawVal === 'object' && rawVal !== null) ? (rawVal.声望值 || 0) : (rawVal || 0);
        // 获取额外信息（如果有）
        const extraInfo = (typeof rawVal === 'object' && rawVal.局势) ? rawVal.局势 : '';

        const p = (val+100)/2;
        const c = val>0?'#4f8':(val<0?'#f55':'#888');

        sHtml += `
          <div style="background:rgba(0,0,0,0.3);padding:6px;border-radius:4px;border:1px solid #333">
            <div style="display:flex;justify-content:space-between;font-size:10px;margin-bottom:4px">
              <span style="color:#aaa">${k} <span style="font-size:9px;color:#666">${extraInfo}</span></span>
              <span style="color:${c};font-weight:bold">${val>0?'+':''}${val}</span>
            </div>
            <div style="height:4px;background:#222;border-radius:2px;overflow:hidden">
              <div style="height:100%;width:${p}%;background:${c};transition:width 0.5s"></div>
            </div>
          </div>`;
      });
      sHtml += '</div>';
      $('#social-list').html(sHtml);
    }

    async function init() {
      createStarfield();
      await waitGlobalInitialized('Mvu');
      render();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, render);
    }
    $(errorCatched(init));
  </script>
</head>
