    <script>
    (function() {
        var myScript = document.currentScript;
        var myWrapper = myScript.parentElement;

        var rawContainer = myWrapper.querySelector('.bg3-raw-data');
        var targetContainer = myWrapper.querySelector('.bg3-card-container');

        if (!rawContainer || !targetContainer) return;

        try {
            var rawJson = rawContainer.innerText.trim();
            rawJson = rawJson.replace(/,\s*}/g, '}').replace(/,\s*]/g, ']'); 
            var data = JSON.parse(rawJson);

            var action = data['行动'] || '行动检定';
            var type = data['检定类型'] || '属性检定';
            var formula = data['公式详情'] || '';
            var finalVal = data['最终结果'] || 0;
            var dc = data['难度等级_DC'] || 10;
            var outcome = data['判定结论'] || '未知';

            var isCritFail = outcome.includes('大失败');
            var isCritSuccess = outcome.includes('大成功');
            var isSuccess = outcome.includes('成功') || (!outcome.includes('失败') && finalVal >= dc);

            var themeColor = isSuccess ? '#4ce6ff' : '#ff4444';
            var secondaryColor = isSuccess ? '#00ff88' : '#ff6b6b';
            if (isCritSuccess) { themeColor = '#ffd700'; secondaryColor = '#ffaa00'; }
            if (isCritFail) { themeColor = '#ff0044'; secondaryColor = '#880022'; }

            var outcomeText = isSuccess ? 'SUCCESS' : 'FAILURE';
            if (isCritFail) outcomeText = 'CRITICAL MISS';
            if (isCritSuccess) outcomeText = 'CRITICAL HIT';

            var uid = 'roll_' + Math.random().toString(36).substr(2, 9);

            var particles = '';
            var particleCount = (isCritSuccess || isCritFail) ? 20 : 12;
            for (var i = 0; i < particleCount; i++) {
                var left = Math.random() * 100;
                var delay = Math.random() * 3;
                var duration = 2 + Math.random() * 3;
                var size = 2 + Math.random() * 4;
                particles += '<div class="' + uid + '-particle" style="left:' + left + '%;animation-delay:' + delay + 's;animation-duration:' + duration + 's;width:' + size + 'px;height:' + size + 'px;"></div>';
            }

            var stars = '';
            if (isCritSuccess || isCritFail) {
                for (var j = 0; j < 8; j++) {
                    var starLeft = 10 + Math.random() * 80;
                    var starTop = 10 + Math.random() * 80;
                    var starDelay = Math.random() * 1;
                    stars += '<div class="' + uid + '-star" style="left:' + starLeft + '%;top:' + starTop + '%;animation-delay:' + starDelay + 's;"></div>';
                }
            }

            var html = `
            <style>
                /* [修复] 在 100% 关键帧显式添加 opacity: 1 */
                @keyframes ${uid}-cardEntry {
                    0% { opacity: 0; transform: perspective(600px) rotateX(-15deg) translateY(-40px) scale(0.9); filter: blur(10px); }
                    60% { opacity: 1; transform: perspective(600px) rotateX(5deg) translateY(5px) scale(1.02); filter: blur(0); }
                    100% { opacity: 1; transform: perspective(600px) rotateX(0) translateY(0) scale(1); filter: blur(0); }
                }

                @keyframes ${uid}-textFadeIn {
                    0% { opacity: 0; transform: translateY(-10px); }
                    100% { opacity: 1; transform: translateY(0); }
