                    0% { opacity: 0; transform: scale(0) rotateZ(0deg); }
                    20% { opacity: 1; }
                    40% { transform: scale(1.3) rotateZ(180deg); }
                    60% { transform: scale(0.9) rotateZ(360deg); }
                    80% { transform: scale(1.1) rotateZ(540deg); }
                    100% { transform: scale(1) rotateZ(720deg); }
                }

                @keyframes ${uid}-numberReveal {
                    0%, 70% { opacity: 0; transform: translateY(20px) scale(0.5); filter: blur(10px); }
                    85% { transform: translateY(-5px) scale(1.15); filter: blur(0); }
                    100% { opacity: 1; transform: translateY(0) scale(1); }
                }

                @keyframes ${uid}-numberPulse {
                    0%, 100% { text-shadow: 0 0 10px ${themeColor}, 0 0 20px ${themeColor}, 0 0 30px ${themeColor}66; transform: scale(1); }
                    50% { text-shadow: 0 0 20px ${themeColor}, 0 0 40px ${themeColor}, 0 0 60px ${themeColor}, 0 0 80px ${themeColor}44; transform: scale(1.05); }
                }

                @keyframes ${uid}-hexPulse {
                    0%, 100% { stroke-width: 2; filter: drop-shadow(0 0 5px ${themeColor}); }
                    50% { stroke-width: 3; filter: drop-shadow(0 0 15px ${themeColor}) drop-shadow(0 0 25px ${themeColor}66); }
                }

                @keyframes ${uid}-hexRotate {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                }

                @keyframes ${uid}-ringExpand {
                    0% { transform: translate(-50%, -50%) scale(0); opacity: 0.8; border-width: 3px; }
