                @keyframes ${uid}-critShake {
                    0%, 100% { transform: translateX(0); }
                    10%, 30%, 50%, 70%, 90% { transform: translateX(-2px); }
                    20%, 40%, 60%, 80% { transform: translateX(2px); }
                }

                @keyframes ${uid}-vsLine {
                    0% { width: 0; opacity: 0; }
                    100% { width: 40px; opacity: 1; }
                }

                .${uid}-particle {
                    position: absolute;
