                    animation: ${uid}-star 1.5s ease-in-out infinite;
                    pointer-events: none;
                    z-index: 6;
                }
            </style>

            <div style="
                font-family: 'Cinzel', 'Times New Roman', serif;
                background: linear-gradient(180deg, #1c1c1c 0%, #0a0a0a 50%, #111 100%);
                border: 2px solid #3a3a3a;
