                box-sizing: border-box;
                /* 修复动画结束后透明度问题 */
                animation: ${uid}-cardEntry 0.8s cubic-bezier(0.34, 1.56, 0.64, 1) forwards, 
                           ${uid}-borderGlow 3s ease-in-out 1s infinite
                           ${isCritFail ? ', ' + uid + '-critShake 0.5s ease 0.3s' : ''};
            ">
                <!-- 顶部装饰线 -->
                <div style="
                    position: absolute;
                    top: 0; left: 10%; right: 10%;
                    height: 2px;
                    background: linear-gradient(90deg, transparent, ${themeColor}, transparent);
                    opacity: 0.7;
                "></div>

                <!-- 背景纹理 -->
                <div style="
