                    background: radial-gradient(circle at center, ${themeColor}66 0%, transparent 70%);
                    animation: ${uid}-critFlash 0.8s ease-out;
                    pointer-events: none;
                "></div>` : ''}

                <!-- 浮动粒子 -->
                ${particles}

                <!-- 闪烁星星 -->
                ${stars}

                <!-- 检定类型: 使用独立的淡入动画，避免继承父级动画问题 -->
                <div style="
                    font-size: 11px; 
                    color: #9e8445; 
                    letter-spacing: 3px; 
                    text-transform: uppercase; 
                    margin-bottom: 5px;
                    opacity: 0;
                    animation: ${uid}-textFadeIn 0.5s ease-out 0.2s forwards;
                    text-shadow: 0 0 10px #9e844566;
                ">
                    ◆ ${type} ◆
                </div>

                <!-- 行动名称 -->
                <div style="
                    font-size: 17px; 
