<!doctype html>
<html lang="zh-CN">
<head>
  <style>
  /* === 字体与基础设置 === */
  @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Noto+Sans+SC:wght@400;500;700&family=Share+Tech+Mono&display=swap');

  :root {
    /* 核心变量 */
    --theme-color: #ffcc66;
    --theme-glow: #ffcc6680;
    --theme-bg: #0a0a0f;
    --theme-dim: rgba(255, 204, 102, 0.15);

    /* 背景色 */
    --bg-panel: #111316;

    /* 状态色 */
    --c-hp: #ff4466;
    --c-xp: #44ddff;
    --c-shield: #44aaff;
  }

  * { box-sizing: border-box; }

  body {
    margin: 0; padding: 0;
    font-family: 'Noto Sans SC', sans-serif;
    font-size: 13px;
    background: transparent;
    color: #e0e0e0;
    overflow: hidden;
    user-select: none;
  }

  /* === 粒子背景 (静态) === */
  .starfield {
    position: fixed; inset: 0; pointer-events: none; z-index: -1; overflow: hidden;
  }
  .star {
    position: absolute; width: 2px; height: 2px; background: #fff;
    border-radius: 50%; opacity: 0.6; /* 静态透明度 */
  }

  /* === 外壳框架 === */
  .arcane-slate {
    position: relative; width: 98%; margin: 10px auto;
    background: #000; border: 1px solid rgba(255, 204, 102, 0.3);
    padding: 6px; box-shadow: 0 10px 20px rgba(0,0,0,0.8);
  }

  /* === 屏幕容器 === */
  .screen-container { 
    position: relative; height: 450px; overflow: hidden;
    background: var(--bg-panel);
    background-image: linear-gradient(180deg, var(--bg-panel) 0%, rgba(0,0,0,0.3) 100%);
    box-shadow: inset 0 0 60px var(--theme-dim); 
    border: 1px solid rgba(255, 255, 255, 0.1); 
  }
  .crt-screen { 
    position: relative; height: 450px; overflow: hidden;
    background: linear-gradient(180deg, var(--theme-bg) 0%, #050508 100%);
    border: 1px solid rgba(255,255,255,0.1);
    box-shadow: inset 0 0 40px rgba(0,0,0,0.8);
    border-radius: 2px;
  }

  /* === 装饰 (静态) === */
  .corner-deco {
    position: absolute; width: 10px; height: 10px; z-index: 20;
    border-color: var(--theme-color); border-style: solid; border-width: 0;
    box-shadow: 0 0 4px var(--theme-color); pointer-events: none;
  }
  .tl { top: -1px; left: -1px; border-top-width: 2px; border-left-width: 2px; }
  .tr { top: -1px; right: -1px; border-top-width: 2px; border-right-width: 2px; }
  .bl { bottom: -1px; left: -1px; border-bottom-width: 2px; border-left-width: 2px; }
  .br { bottom: -1px; right: -1px; border-bottom-width: 2px; border-right-width: 2px; }

  /* 静态扫描线纹理，移除动画 */
  .scanlines {
    position: absolute; inset: 0; pointer-events: none; z-index: 10;
    background: repeating-linear-gradient(0deg, transparent 0px, transparent 1px, rgba(0,0,0,0.3) 1px, rgba(0,0,0,0.3) 2px);
    opacity: 0.2; 
  }

  /* 移除 .scan-beam (光束扫描) */

  .screen-content {
    height: 100%; overflow-y: auto; padding: 15px; position: relative; z-index: 15;
    scrollbar-width: none;
  }
  .screen-content::-webkit-scrollbar { display: none; }

  /* === 导航栏 === */
  .nav-bar {
    display: flex; justify-content: space-around;
    background: #15151a; border-top: 1px solid rgba(255,255,255,0.1);
    padding: 6px 0; margin-top: 4px;
  }
  .nav-btn {
    background: none; border: none; color: #666;
    font-family: 'Orbitron', sans-serif; font-size: 10px; font-weight: 700;
    padding: 6px 10px; cursor: pointer; transition: all 0.2s;
    text-transform: uppercase; letter-spacing: 1px;
  }
  .nav-btn:hover { color: #aaa; }
  .nav-btn.active {
    color: var(--theme-color); background: var(--theme-dim);
    border-radius: 4px; text-shadow: 0 0 5px var(--theme-glow);
  }

  /* === 内部组件 === */
  .section-title {
    font-family: 'Orbitron', sans-serif; font-size: 11px; font-weight: 700;
    color: var(--theme-color); margin: 20px 0 10px 0; border-bottom: 1px solid var(--theme-dim);
    padding-bottom: 4px; display: flex; align-items: center; gap: 6px;
  }

