          aHtml += `<div class="list-card ${getQClass(i.品质)}" onclick="toggleDetail(this)">
            <div class="card-head"><span class="card-title">${i.名称}</span><span style="color:var(--theme-color)">x${i.数量||1}</span></div>
            <div class="card-detail">品质: ${i.品质}<br>属性: ${i.属性}<br>${i.描述}</div>
          </div>`;
        });
      } else {
        aHtml += '<div class="empty-state">背包为空</div>';
      }
      $('#asset-list').html(aHtml);

      // === PAGE 5: SOCIAL ===
      const soc = hero.人脉||{};
      let sHtml = '';
      let impH='<div class="section-title">⭐ 重要关系</div>', normH='<div class="section-title">👥 泛泛之交</div>';
      const enemyName = target.名称 || '';

      Object.entries(soc).forEach(([k,v]) => {
        if (k === enemyName) return; 

        let det=''; 
        Object.entries(v).forEach(([kk,vv])=> {
            if (typeof vv !== 'object' && kk !== '属性') det+=`${kk}: ${vv}<br>`;
        });

        const item = `<div class="list-card" style="border-color:${v.类型==='重要'?'var(--theme-color)':'#444'}" onclick="toggleDetail(this)">
          <div class="card-head"><span class="card-title" style="color:${v.类型==='重要'?'#fff':'#ccc'}">${k}</span><span style="font-weight:bold;color:${v.好感度>0?'#4f8':'#f55'}">${v.好感度}</span></div>
          <div class="card-sub">${v.种族} | ${v.关系||'未知'}</div>
          <div class="card-detail">${det}</div>
        </div>`;
        v.类型==='重要'?impH+=item:normH+=item;
      });
      sHtml += impH + normH;

      // 势力声望 (已修复对象读取)
      sHtml += '<div class="section-title">🏛️ 势力声望</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
      const reps = _.get(all, 'stat_data.势力声望', {});

      Object.entries(reps).forEach(([k, rawVal]) => {
        // 兼容处理：如果是新版对象结构取.声望值，如果是旧版数字直接用
        const val = (typeof rawVal === 'object' && rawVal !== null) ? (rawVal.声望值 || 0) : (rawVal || 0);
        // 获取额外信息（如果有）
        const extraInfo = (typeof rawVal === 'object' && rawVal.局势) ? rawVal.局势 : '';

        const p = (val+100)/2;
        const c = val>0?'#4f8':(val<0?'#f55':'#888');

        sHtml += `
          <div style="background:rgba(0,0,0,0.3);padding:6px;border-radius:4px;border:1px solid #333">
            <div style="display:flex;justify-content:space-between;font-size:10px;margin-bottom:4px">
              <span style="color:#aaa">${k} <span style="font-size:9px;color:#666">${extraInfo}</span></span>
              <span style="color:${c};font-weight:bold">${val>0?'+':''}${val}</span>
            </div>
            <div style="height:4px;background:#222;border-radius:2px;overflow:hidden">
              <div style="height:100%;width:${p}%;background:${c};transition:width 0.5s"></div>
            </div>
          </div>`;
      });
      sHtml += '</div>';
      $('#social-list').html(sHtml);
    }

    async function init() {
      createStarfield();
      await waitGlobalInitialized('Mvu');
      render();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, render);
    }
    $(errorCatched(init));
  </script>
</head>
