import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// === 基础常量 ===
const DEFAULT_STATS = { 格斗技艺: 30, 射击技艺: 30, 力量: 30, 韧性: 30, 敏捷: 30, 智力: 30, 感知: 30, 意志: 30, 魅力: 30 };
const RACE_BASE_STATS = {
  '人族': { ...DEFAULT_STATS },
  '萨尔贡': { ...DEFAULT_STATS, 力量: 25, 韧性: 25, 敏捷: 40, 智力: 40, 意志: 45, 魅力: 35 },
  '灵族': { ...DEFAULT_STATS, 力量: 25, 韧性: 25, 敏捷: 40, 智力: 40, 意志: 45, 魅力: 35 },
  '巴洛克': { ...DEFAULT_STATS, 格斗技艺: 40, 力量: 45, 韧性: 45, 智力: 20, 魅力: 20, 敏捷: 35 },
  '兽族': { ...DEFAULT_STATS, 格斗技艺: 40, 力量: 45, 韧性: 45, 智力: 20, 魅力: 20, 敏捷: 35 },
  '巴洛克混血': { ...DEFAULT_STATS, 格斗技艺: 35, 力量: 40, 韧性: 40, 敏捷: 35, 感知: 35 },
  '半兽人': { ...DEFAULT_STATS, 格斗技艺: 35, 力量: 40, 韧性: 40, 敏捷: 35, 感知: 35 },
  '纽特': { ...DEFAULT_STATS, 格斗技艺: 20, 力量: 20, 韧性: 20, 智力: 45, 感知: 40, 意志: 45 },
  '扎尔': { ...DEFAULT_STATS, 意志: 20, 韧性: 25, 敏捷: 45, 魅力: 50, 格斗技艺: 35 },
  '纳卡': { ...DEFAULT_STATS, 感知: 45, 敏捷: 40, 魅力: 20, 射击技艺: 40 },
  '塔萨达': { ...DEFAULT_STATS, 智力: 45, 韧性: 35, 敏捷: 25, 意志: 35 },
  '弗洛拉': { ...DEFAULT_STATS, 韧性: 40, 感知: 40, 敏捷: 20, 智力: 25, 格斗技艺: 25 },
  '虫族': { ...DEFAULT_STATS },
  '虫群': { ...DEFAULT_STATS },
};
const calculateBonus = (val) => Math.floor(((val || 30) - 30) / 10);

// === 子 Schema 定义 ===
const TagSchema = z.object({
  名字: z.string().catch('未知标签'),
  描述: z.string().catch('无描述'),
  效果: z.string().catch('无特殊效果'),
}).catch({ 名字: '错误', 描述: '无', 效果: '无' });

const ItemSchema = z.object({
  名称: z.string().catch('未知物品'),
  类型: z.string().catch('杂物'), 
  品质: z.enum(['破损', '废物', '普通', '精良', '稀有', '史诗', '传说', '神话']).catch('普通'),
  数量: z.coerce.number().int().prefault(1), 
  属性: z.string().catch('无'), 
  描述: z.string().optional(),
}).catch({ 名称: '损坏', 类型: '错误', 数量: 1 });

const EquipSlotSchema = z.object({
  名称: z.string().prefault('无'),
  类型: z.string().optional(),
  品质: z.string().optional(),
  属性: z.string().optional(),
  描述: z.string().optional(),
  当前耐久: z.coerce.number().optional(),
  最大耐久: z.coerce.number().optional(),
}).prefault({ 名称: '无' });

const VehicleSchema = z.object({
  名称: z.string().prefault('无'),
  类型: z.string().optional(),
  稀有度: z.string().optional(),
  描述: z.string().optional(),
  配置: z.object({ 主武器: z.string().optional(), 副武器: z.string().optional(), 护盾: z.string().optional() }).optional(),
  参数: z.object({ 装甲强度: z.coerce.number().optional(), 机动性: z.coerce.number().optional(), 火力: z.coerce.number().optional() }).optional(),
  状态: z.object({ 当前耐久: z.coerce.number().prefault(100), 最大耐久: z.coerce.number().prefault(100), 能源: z.coerce.number().prefault(100) }).prefault({}),
}).prefault({});

const MissionSchema = z.object({
  类型: z.string().catch('委托'), 
  状态: z.enum(['进行中', '可交付', '已完成', '失败']).catch('进行中'), 
  说明: z.string().catch('无详细说明'),
  进度: z.string().catch('进行中'), 
  奖励: z.string().optional(), 
  惩罚: z.string().optional(), 
}).catch({ 状态: '进行中', 说明: '数据读取错误' });

const ContactSchema = z.object({
  类型: z.enum(['普通', '重要']).catch('普通'),
  种族: z.string().catch('人族'),
  势力: z.string().catch('中立'),
  好感度: z.coerce.number().catch(0),
  等级: z.coerce.number().optional(),
  星能: z.string().optional(),
  关系: z.string().optional(),
  外貌: z.string().optional(),
  属性: z.record(z.string(), z.number()).optional(),
}).catch({ 种族: '未知' });

const CombatTargetSchema = z.object({
  名称: z.string().prefault('无'),
  级别: z.string().prefault('未知'),
  当前生命: z.coerce.number().prefault(100), 
  最大生命: z.coerce.number().prefault(100),
  护盾: z.coerce.number().prefault(0),
  状态: z.record(z.string(), z.boolean()).prefault({}),
}).prefault({ 名称: '无', 当前生命: 100, 最大生命: 100 });

// === [NEW] 势力详情 Schema ===
const FactionSchema = z.object({
  声望值: z.coerce.number().default(0),
  类型: z.string().default('未知势力'), // 大型势力, 组织, 跨国公司
  局势: z.string().default('稳定'),
  子派系: z.string().optional(), // 自然语言描述，如 "王党(崇拜), 议会(敌对)"
  年代纪: z.array(z.string()).optional(), // 历史事件列表
  可删除: z.boolean().default(true), // 标记是否为预设势力
});

// 预设不可删除的势力列表
const PRESET_FACTIONS = ['奥古斯都帝国', '天琴联邦', '圣临教团', '萨尔贡议会', '巴洛克合众国', '纽特财团', '自由星域', '猩红教团'];

const ArchiveSchema = z.object({ 结果: z.string(), 时间: z.string() });

// === 主 Schema ===
export const Schema = z.object({
  世界: z.object({
    星历时间: z.string().prefault('新纪元 1024年'),
    当前位置: z.string().prefault('未知星域'),
  }).prefault({}),

  战斗目标: CombatTargetSchema,

  主角: z.object({
    信息: z.object({
      姓名: z.string().prefault('待定'),
      种族: z.string().prefault('人族'),
      职业: z.string().prefault('流浪者'),
      星能: z.string().prefault('无'),
      星能等级: z.string().prefault('无'), 
      身份标签: z.record(z.string(), TagSchema).prefault({}),
    }).prefault({}),
    状态: z.object({
      当前生命: z.coerce.number().prefault(100),
      最大生命: z.coerce.number().prefault(100),
      护盾值: z.coerce.number().prefault(0),
      灵能槽: z.coerce.number().prefault(0),
    }).prefault({}),
    成长: z.object({
      等级: z.coerce.number().min(1).max(20).prefault(1),
      经验值: z.coerce.number().prefault(0),
      升级所需XP: z.coerce.number().prefault(1000),
      剩余属性点: z.coerce.number().prefault(0),
    }).prefault({}),
    重大历史经历: z.record(z.string(), z.object({
      事件名: z.string(), 发生时间: z.string(), 描述: z.string(), 传阅度: z.string(),
    })).prefault({}),
    属性: z.object({
      格斗技艺: z.coerce.number().prefault(30), 射击技艺: z.coerce.number().prefault(30),
      力量: z.coerce.number().prefault(30), 韧性: z.coerce.number().prefault(30),
      敏捷: z.coerce.number().prefault(30), 智力: z.coerce.number().prefault(30),
      感知: z.coerce.number().prefault(30), 意志: z.coerce.number().prefault(30),
      魅力: z.coerce.number().prefault(30),
    }).prefault({}),
    属性加值: z.record(z.string(), z.number()).optional(),
    阵营: z.object({
      秩序偏向: z.coerce.number().prefault(0), 善恶偏向: z.coerce.number().prefault(0),
    }).prefault({}),
    资源: z.object({ 信用点: z.coerce.number().prefault(1000) }).prefault({}),
    载具: z.object({ 当前机甲: VehicleSchema, 当前舰船: VehicleSchema }).prefault({}),
    装备栏: z.object({ 主手: EquipSlotSchema, 副手: EquipSlotSchema, 护甲: EquipSlotSchema, 饰品: EquipSlotSchema, 背包物品: z.record(z.string(), ItemSchema).prefault({}) }).prefault({}),
    人脉: z.record(z.string(), ContactSchema).prefault({}),
  })
  .prefault({})
  .transform(hero => {
    // 属性加值计算
    if (hero.属性) hero.属性加值 = _.mapValues(hero.属性, calculateBonus);
    // 自动升级逻辑
    if (hero.成长) {
       const getNextExp = (lvl) => lvl * 1000;
       if (!hero.成长.升级所需XP) hero.成长.升级所需XP = getNextExp(hero.成长.等级);

       // 检测是否为虫族
       const race = hero.信息?.种族 || '';
       const isSwarm = (race.includes('虫族') || race.includes('虫群') || race.includes('Swarm'));
       const pointsPerLevel = isSwarm ? 10 : 5; // 虫族得10点，其他得5点

       let loops = 0;
       while (hero.成长.经验值 >= hero.成长.升级所需XP && loops++ < 5) {
         if (hero.成长.等级 >= 20) break;
         hero.成长.经验值 -= hero.成长.升级所需XP;
         hero.成长.等级 += 1;
         hero.成长.剩余属性点 += pointsPerLevel; // 应用差异化属性点
         hero.成长.升级所需XP = getNextExp(hero.成长.等级);
       }
    }

    // 最大生命值逻辑
    if (hero.状态) {
       const baseHp = hero.属性?.韧性 || 30;
       const strBonus = Math.floor((hero.属性?.力量 || 30) * 0.2);
       const lvlBonus = (hero.成长?.等级 || 1) * 10;
       hero.状态.最大生命 = baseHp + strBonus + lvlBonus;
       hero.状态.当前生命 = _.clamp(hero.状态.当前生命, 0, hero.状态.最大生命);
    }
    // 物品清理逻辑
    if (hero.装备栏?.背包物品) hero.装备栏.背包物品 = _.pickBy(hero.装备栏.背包物品, (item) => item.数量 > 0);
    // NPC 逻辑
    if (hero.人脉) {
      Object.keys(hero.人脉).forEach(key => {
        const npc = hero.人脉[key];
        npc.好感度 = _.clamp(npc.好感度 || 0, -100, 100);
        if (npc.种族 && RACE_BASE_STATS[npc.种族] && (!npc.属性 || _.isEmpty(npc.属性))) {
            npc.属性 = { ...RACE_BASE_STATS[npc.种族] };
        }
      });
    }
    return hero;
  }),

  当前任务: z.record(z.string(), MissionSchema).prefault({}),
  任务档案: z.record(z.string(), ArchiveSchema).prefault({}),

  // [NEW] 势力声望升级逻辑
  势力声望: z.record(z.string(), z.any()) // 先接受 any 以兼容旧数据
    .prefault({})
    .transform(factions => {
       const newFactions = {};
       Object.keys(factions).forEach(key => {
         const val = factions[key];
         // 如果是旧数据(数字)，升级为对象
         if (typeof val === 'number') {
           newFactions[key] = {
             声望值: val,
             类型: PRESET_FACTIONS.includes(key) ? '大型势力' : '组织',
             局势: '稳定',
             可删除: !PRESET_FACTIONS.includes(key)
           };
         } else {
           // 已经是对象，应用 Schema 解析
           try {
             newFactions[key] = FactionSchema.parse(val);
             // 强制修正不可删除属性
             if (PRESET_FACTIONS.includes(key)) newFactions[key].可删除 = false;
           } catch(e) {
             console.error('Faction schema error:', e);
             newFactions[key] = { 声望值: 0, 类型: '数据错误', 局势: '未知' };
           }
         }
       });
       return newFactions;
    })
})
.transform(data => {
  // 任务清理逻辑
  const active = data.当前任务 || {};
  const finishedTasks = _.pickBy(active, (task) => task.状态 === '已完成' || task.状态 === '失败');
  if (!_.isEmpty(finishedTasks)) {
     const newArchives = _.mapValues(finishedTasks, t => ({ 结果: t.状态, 时间: data.世界.星历时间 }));
     data.任务档案 = { ...data.任务档案, ...newArchives };
     data.当前任务 = _.pickBy(active, (task) => task.状态 !== '已完成' && task.状态 !== '失败');
  }
  return data;
});

$(() => {
  registerMvuSchema(Schema);
})

